#nullable enable // autogenerated

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Effects;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Level;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.burnAtDay)]
    public class BurnAtDayBehaviour : EntityBehaviourDefinition
    {
        public BurnAtDayBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            var interval = entity.GetProperty<int>(PROP_BURN_INTERVAL);
            if (entity.IsTimeInterval(interval) & !entity.IsInWater() && entity.Level.IsDay() && entity.GetMainArmor() == null)
            {
                var effects = new DamageEffectList(VanillaDamageEffects.FIRE, VanillaDamageEffects.SELF_DAMAGE, VanillaDamageEffects.IGNORE_ARMOR);
                entity.TakeDamage(entity.GetProperty<float>(PROP_BURN_DAMAGE), effects, entity);
                entity.Spawn(VanillaEffectID.fireburn, entity.Position);
            }
        }
        public static readonly VanillaEntityPropertyMeta<int> PROP_BURN_INTERVAL = new VanillaEntityPropertyMeta<int>("burn_interval", 15);
        public static readonly VanillaEntityPropertyMeta<float> PROP_BURN_DAMAGE = new VanillaEntityPropertyMeta<float>("burn_damage", 50f);
    }
}
